document.addEventListener("DOMContentLoaded",function(){const s=document.querySelectorAll("section[id]"),c=document.querySelectorAll(".nav-links a");function i(){let o=window.pageYOffset;s.forEach(e=>{const l=e.offsetHeight,n=e.offsetTop-100,f=e.getAttribute("id");c.forEach(t=>{t.getAttribute("href")==="#"+f&&(o>n&&o<=n+l?(t.style.color="#000",t.style.fontWeight="600"):(t.style.color="",t.style.fontWeight=""))})})}window.addEventListener("scroll",i)});
